func combinations(arr [][2]int, k int) [][2]int {
    var result [][2]int
    var backtrack func(start int, current [][2]int)
    backtrack = func(start int, current [][2]int) {
        if len(current) == k {
            result = append(result, current)
            return
        }
        for i := start; i < len(arr); i++ {
            current = append(current, arr[i])
            backtrack(i+1, current)
            current = current[:len(current)-1]
        }
    }
    backtrack(0, [][2]int{})
    return result
}
